        return -1;
      }
      if (head.next == null) {
        int data = head.data;
        Node node = head;
        head = head.next;
        if (head == null) {
          tail = head;
        }
        node = null;
        return data;
      }

      int data = tail.data;
      Node node = tail;
      tail = tail.prev;
