class Solution {
  constructor() {
    this.head = null;
    this.tail = null;
  }

  add(data) {
    // Add the data to the tail of the queue
    const node = new Node(data);
    if (this.head == null) {
      this.head = node;
      this.tail = node;
    } else {
      this.tail.next = node;
      node.prev = this.tail;
      this.tail = node;
    }
  }

  poll() {
    if (this.head == null) {
      console.log("poll: queue is empty");
      return -1;
    }
    if (this.head.next == null) {
      const data = this.head.data;
      const node = this.head;
      this.head = this.head.next;
      if (this.head == null) {
        this.tail = this.head;
      }
      node = null;
      return data;
    }

    const data = this.tail.data;
    const node = this.tail;
    this.tail = this.tail.prev;
    if (this.tail == null) {
      this.head = this.tail;
    }
    node = null;
    return data;
  }

  static main() {
    const s = new Solution();
    const readline = require("readline");
    const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
    let n;
    rl.question("", (input) => {
      n = parseInt(input);
      let i = 0;
      function readNext() {
        if (i < n) {
          s.add(parseInt(rl.question(""),
          (input) => {
            i++;
            readNext();
          }
          ));
        } else {
          rl.close();
        }
      }
      readNext();
    });
    rl.on("close", () => {
      while (s.head) {
        process.stdout.write(s.poll() + " ");
        s.poll();
      }
      console.log();
    });
  }
}
